# Function to encode text
def encode_text(text):
    return model.encode(text)

# Load cleaned course descriptions
courses_df = pd.read_excel('C:/Users/13054/Desktop/Re-created jobspy project/course_descriptions.xlsx')

# Load cleaned job descriptions
jobs_df = pd.read_excel('C:/Users/13054/Desktop/Re-created jobspy project/cleaned_jobs.xlsx')

# Calculate embeddings for course and job descriptions
courses_df['embedding'] = courses_df['filtered_description'].apply(encode_text)
jobs_df['embedding'] = jobs_df['cleaned_description'].apply(encode_text)

# Initialize a list to hold the results
matching_results = []

# Compare each course with each job
for _, course in courses_df.iterrows():
    course_embedding = course['embedding']
    for _, job in jobs_df.iterrows():
        job_embedding = job['embedding']
        similarity = util.pytorch_cos_sim(course_embedding, job_embedding).item()
        matching_results.append({
            'Course Name': course['course_name'],
            'Job Title': job['title'],
            'Similarity': similarity,
            'Salary': job['mean_salary'],
            'Is Core': course['is_core']
        })

# Convert results to DataFrame
matches_df = pd.DataFrame(matching_results)
print(matches_df)

# Export the results to a CSV file
matches_path = 'C:/Users/13054/Desktop/Re-created jobspy project/Datasets/matching.csv'
matches_df.to_csv(matches_path, index=False)

print("Matching results saved to", matches_path)
